// Fetch cold leads from Activix CRM
// GET /v2/leads with filters for pending/attempted, new/used divisions

const ACTIVIX_API_URL = 'https://api.activix.ca/v2/leads';
const ACTIVIX_TOKEN = $env.ACTIVIX_API_TOKEN || '';

const excludeResults = ['lost', 'invalid', 'duplicate', 'delivered', 'sold'];
const includeDivisions = ['new', 'used'];

let allLeads = [];
let page = 1;
const perPage = 100;
let hasMore = true;

while (hasMore) {
  const params = new URLSearchParams({
    page: String(page),
    per_page: String(perPage),
    'result[]': 'pending',
    'division[]': 'new',
  });

  params.append('result[]', 'attempted');
  params.append('division[]', 'used');

  const response = await fetch(`${ACTIVIX_API_URL}?${params.toString()}`, {
    method: 'GET',
    headers: {
      'Authorization': `Bearer ${ACTIVIX_TOKEN}`,
      'Content-Type': 'application/json',
      'Accept': 'application/json',
    },
  });

  if (!response.ok) {
    throw new Error(`Activix API error: ${response.status} ${response.statusText}`);
  }

  const data = await response.json();
  const leads = data.data || [];

  const filtered = leads.filter(lead => {
    if (excludeResults.includes(lead.result)) return false;
    if (!includeDivisions.includes(lead.division)) return false;
    return true;
  });

  allLeads = allLeads.concat(filtered);

  if (leads.length < perPage) {
    hasMore = false;
  } else {
    page++;
  }

  if (page > 10) hasMore = false;
}

return [{ json: { leads: allLeads, totalFetched: allLeads.length, fetchedAt: new Date().toISOString() } }];

// Filter eligible leads:
// 1. Exclude unsubscribed
// 2. Filter to leads due for next touch based on cadence schedule
//    Day 0=instant (Epic 9), Day 2, 4, 7, 14, 30, 60+

const input = $input.first().json;
const leads = input.leads || [];
const now = new Date();

const TOUCH_SCHEDULE = {
  2: 2, 3: 4, 4: 7, 5: 14, 6: 30, 7: 60,
};

const MONTHLY_INTERVAL = 30;

function daysSinceCreation(createdAt) {
  const created = new Date(createdAt);
  return Math.floor((now.getTime() - created.getTime()) / (1000 * 60 * 60 * 24));
}

function isUnsubscribed(lead) {
  return !!(lead.unsubscribe_all_date || (lead.unsubscribe_sms_date && lead.unsubscribe_email_date));
}

function determineTouchNumber(lead) {
  const days = daysSinceCreation(lead.created_at);
  if (days < 2) return null;
  let touchNumber = 1;
  for (const [touch, dayThreshold] of Object.entries(TOUCH_SCHEDULE)) {
    if (days >= dayThreshold) touchNumber = parseInt(touch);
  }
  if (days > 60) {
    const extraMonths = Math.floor((days - 60) / MONTHLY_INTERVAL);
    touchNumber = 7 + extraMonths;
  }
  return touchNumber;
}

function isTouchDueToday(lead, touchNumber) {
  const days = daysSinceCreation(lead.created_at);
  if (touchNumber <= 7) {
    const touchDay = TOUCH_SCHEDULE[touchNumber];
    if (!touchDay) return false;
    const nextTouchDay = TOUCH_SCHEDULE[touchNumber + 1] || touchDay + MONTHLY_INTERVAL;
    return days >= touchDay && days < nextTouchDay;
  }
  const touchDay = 60 + (touchNumber - 7) * MONTHLY_INTERVAL;
  const nextTouchDay = touchDay + MONTHLY_INTERVAL;
  return days >= touchDay && days < nextTouchDay;
}

const eligibleLeads = [];

for (const lead of leads) {
  if (isUnsubscribed(lead)) continue;
  const touchNumber = determineTouchNumber(lead);
  if (touchNumber === null) continue;
  if (!isTouchDueToday(lead, touchNumber)) continue;
  eligibleLeads.push({
    ...lead,
    _touchNumber: touchNumber,
    _daysSinceCreation: daysSinceCreation(lead.created_at),
  });
}

return [{ json: { leads: eligibleLeads, eligibleCount: eligibleLeads.length, processedAt: new Date().toISOString() } }];

// Enrich each lead with touch details: channel, strategy, label

const input = $input.first().json;
const leads = input.leads || [];

const CHANNEL_MAP = { 2: 'sms', 3: 'email', 4: 'sms', 5: 'email', 6: 'sms', 7: 'email' };
const STRATEGY_MAP = { 2: 'followup_sms', 3: 'feature_email', 4: 'persistence_sms', 5: 'value_email', 6: 'breakup_sms', 7: 'monthly_email' };

const enrichedLeads = leads.map(lead => {
  const touch = lead._touchNumber;
  const channel = touch >= 7 ? 'email' : (CHANNEL_MAP[touch] || 'email');
  const strategy = touch >= 7 ? 'monthly_email' : (STRATEGY_MAP[touch] || 'monthly_email');
  return { ...lead, _channel: channel, _strategy: strategy, _touchLabel: `Touch ${touch}: ${strategy} via ${channel}` };
});

return enrichedLeads.map(lead => ({ json: lead }));

// Language detection: locale -> area code (Quebec) -> postal code -> en-CA default

const lead = $input.first().json;
const QUEBEC_AREA_CODES = ['418', '438', '450', '514', '579', '581', '819', '873'];
const QUEBEC_POSTAL_PREFIXES = ['G', 'H', 'J'];

function detectLanguage(lead) {
  if (lead.locale) {
    const locale = lead.locale.toLowerCase();
    if (locale.startsWith('fr')) return 'fr-CA';
    if (locale.startsWith('en')) return 'en-CA';
  }
  const phones = lead.phones || [];
  for (const phone of phones) {
    const number = (phone.number || phone.phone || '').replace(/[^0-9]/g, '');
    let areaCode = '';
    if (number.length === 11 && number.startsWith('1')) areaCode = number.substring(1, 4);
    else if (number.length === 10) areaCode = number.substring(0, 3);
    if (QUEBEC_AREA_CODES.includes(areaCode)) return 'fr-CA';
  }
  if (lead.phone) {
    const number = lead.phone.replace(/[^0-9]/g, '');
    let areaCode = '';
    if (number.length === 11 && number.startsWith('1')) areaCode = number.substring(1, 4);
    else if (number.length === 10) areaCode = number.substring(0, 3);
    if (QUEBEC_AREA_CODES.includes(areaCode)) return 'fr-CA';
  }
  const postalCode = lead.postal_code || lead.address?.postal_code || '';
  if (postalCode && QUEBEC_POSTAL_PREFIXES.includes(postalCode.charAt(0).toUpperCase())) return 'fr-CA';
  return 'en-CA';
}

return [{ json: { ...lead, _locale: detectLanguage(lead) } }];

// Inventory match placeholder — in production calls Nexus InventoryService

const lead = $input.first().json;
const vehicles = lead.vehicles || [];
const wantedVehicle = vehicles.find(v => v.type === 'wanted') || vehicles[0] || {};

const inventoryQuery = {
  make: wantedVehicle.make || null,
  model: wantedVehicle.model || null,
  year: wantedVehicle.year || null,
  maxPrice: wantedVehicle.price || null,
};

const vehicleMatches = [];

return [{ json: { ...lead, _inventoryQuery: inventoryQuery, _vehicleMatches: vehicleMatches } }];

// Generate outbound message by touch number and channel
// 2=followup SMS, 3=feature email, 4=persistence SMS, 5=value email, 6=breakup SMS, 7+=monthly email

const lead = $input.first().json;
const touch = lead._touchNumber;
const channel = lead._channel;
const locale = lead._locale || 'en-CA';
const firstName = lead.first_name || lead.name?.split(' ')[0] || 'there';
const vehicleMatch = (lead._vehicleMatches || [])[0] || null;
const vehicleDesc = vehicleMatch
  ? `${vehicleMatch.year} ${vehicleMatch.make} ${vehicleMatch.model}`
  : (lead.vehicles?.[0] ? `${lead.vehicles[0].year || ''} ${lead.vehicles[0].make || ''} ${lead.vehicles[0].model || ''}`.trim() : 'vehicle');

const dealershipName = $env.DEALERSHIP_NAME || 'the dealership';
const repName = lead.advisor?.name || $env.DEFAULT_REP_NAME || 'our team';
const optOut = locale === 'fr-CA'
  ? '
Reply STOP to opt out / Repondez STOP pour vous desabonner'
  : '
Reply STOP to opt out';

const templates = {
  'en-CA': {
    2: { sms: `Hi ${firstName}, just following up from ${dealershipName}! Still interested in the ${vehicleDesc}? Happy to answer any questions. - ${repName}${optOut}` },
    3: { email: { subject: `${firstName}, check out what the ${vehicleDesc} has to offer`, body: `Hi ${firstName},

I wanted to share some highlights about the ${vehicleDesc} you were looking at:

${vehicleMatch?.features?.slice(0, 3).join(', ') || 'Great features available on this model'}

Based on our current listings, we have options that might be a great fit for you. Would you like to schedule a time to take a closer look?

Best regards,
${repName}
${dealershipName}${optOut}` } },
    4: { sms: `Hey ${firstName}, I know life gets busy! Just wanted you to know the ${vehicleDesc} is still available at ${dealershipName}. Want me to hold it for a test drive? - ${repName}${optOut}` },
    5: { email: { subject: `${firstName}, why ${dealershipName} customers love the ${vehicleDesc}`, body: `Hi ${firstName},

I thought you might like to know why the ${vehicleDesc} continues to be one of our most popular choices:

- Strong resale value
- Excellent safety ratings
- Low cost of ownership

Based on our current listings, we still have great options available. I am here whenever you are ready to explore further.

Best regards,
${repName}
${dealershipName}${optOut}` } },
    6: { sms: `Hi ${firstName}, it looks like the timing might not be right for the ${vehicleDesc} -- no worries at all. Whenever you are ready, I am here to help. All the best! - ${repName}, ${dealershipName}${optOut}` },
    7: { email: { subject: `${firstName}, new arrivals at ${dealershipName} you might like`, body: `Hi ${firstName},

We have some exciting new arrivals at ${dealershipName} that match your interest in a ${vehicleDesc}:

Based on our current listings, there are fresh options on the lot. If you would like to see what is new, feel free to reach out anytime.

Best regards,
${repName}
${dealershipName}${optOut}` } },
  },
  'fr-CA': {
    2: { sms: `Bonjour ${firstName}, c'est ${repName} de ${dealershipName}! Toujours interesse(e) par le ${vehicleDesc}? N'hesitez pas si vous avez des questions.${optOut}` },
    3: { email: { subject: `${firstName}, decouvrez le ${vehicleDesc}`, body: `Bonjour ${firstName},

Je voulais partager quelques points forts du ${vehicleDesc} qui vous interessait :

${vehicleMatch?.features?.slice(0, 3).join(', ') || 'Des caracteristiques exceptionnelles disponibles sur ce modele'}

Selon nos inventaires actuels, nous avons des options qui pourraient vous convenir. Aimeriez-vous prendre rendez-vous pour y jeter un coup d'oeil?

Cordialement,
${repName}
${dealershipName}${optOut}` } },
    4: { sms: `Salut ${firstName}, je sais que le temps file! Le ${vehicleDesc} est toujours disponible chez ${dealershipName}. On vous reserve un essai routier? - ${repName}${optOut}` },
    5: { email: { subject: `${firstName}, pourquoi nos clients adorent le ${vehicleDesc}`, body: `Bonjour ${firstName},

Je voulais vous partager pourquoi le ${vehicleDesc} reste un de nos choix les plus populaires :

- Excellente valeur de revente
- Cotes de securite superieures
- Faible cout de possession

Selon nos inventaires actuels, nous avons encore de belles options. Je suis la quand vous serez pret(e).

Cordialement,
${repName}
${dealershipName}${optOut}` } },
    6: { sms: `Bonjour ${firstName}, on dirait que le moment n'est peut-etre pas ideal pour le ${vehicleDesc} -- pas de souci du tout. Je reste disponible quand vous serez pret(e). Bonne continuation! - ${repName}, ${dealershipName}${optOut}` },
    7: { email: { subject: `${firstName}, nouveaux arrivages chez ${dealershipName}`, body: `Bonjour ${firstName},

Nous avons de nouveaux arrivages chez ${dealershipName} qui correspondent a votre interet pour un ${vehicleDesc} :

Selon nos inventaires actuels, il y a des options fraiches sur le terrain. N'hesitez pas a nous contacter si vous voulez voir les nouveautes.

Cordialement,
${repName}
${dealershipName}${optOut}` } },
  },
};

const localeTemplates = templates[locale] || templates['en-CA'];
const touchKey = touch >= 7 ? 7 : touch;
const touchTemplate = localeTemplates[touchKey] || localeTemplates[7];

let message = null;
let subject = null;

if (channel === 'sms' && touchTemplate.sms) {
  message = touchTemplate.sms;
} else if (channel === 'email' && touchTemplate.email) {
  message = touchTemplate.email.body;
  subject = touchTemplate.email.subject;
} else {
  if (touchTemplate.sms) message = touchTemplate.sms;
  else if (touchTemplate.email) { message = touchTemplate.email.body; subject = touchTemplate.email.subject; }
}

return [{ json: { ...lead, _message: message, _emailSubject: subject, _messageGenerated: !!message, _messageLength: message ? message.length : 0 } }];

// Compliance pre-flight: consent (CASL), opt-out, frequency cap, content validation

const lead = $input.first().json;
const message = lead._message || '';
const channel = lead._channel || 'sms';
const now = new Date();

const failures = [];
let pass = true;

// 1. CASL consent check
const consentDate = lead.consent_date ? new Date(lead.consent_date) : (lead.created_at ? new Date(lead.created_at) : null);
const consentType = lead.consent_type || 'implied';
if (consentType === 'implied' && consentDate) {
  const sixMonthsLater = new Date(consentDate);
  sixMonthsLater.setMonth(sixMonthsLater.getMonth() + 6);
  if (now > sixMonthsLater) { failures.push('CASL: Implied consent expired (>6 months)'); pass = false; }
}

// 2. Opt-out check
if (lead.unsubscribe_all_date) { failures.push('Opt-out: Lead has unsubscribed from all communications'); pass = false; }
if (channel === 'sms' && lead.unsubscribe_sms_date) { failures.push('Opt-out: Lead has unsubscribed from SMS'); pass = false; }
if (channel === 'email' && lead.unsubscribe_email_date) { failures.push('Opt-out: Lead has unsubscribed from email'); pass = false; }

// 3. Content validation
const FORBIDDEN_PATTERNS = [
  /\$\d+[\s/]*(per|a|\/)\s*month/i, /monthly\s*payment/i, /paiement\s*mensuel/i,
  /\d+(\.\d+)?\s*%\s*(apr|interest|taux|interet)/i, /interest\s*rate/i, /taux\s*d'interet/i,
  /financ(ing|ement)\s*(term|option|rate|taux)/i, /credit\s*score/i, /cote\s*de\s*credit/i,
  /insurance\s*(rate|cost|premium)/i, /assurance\s*(taux|cout|prime)/i,
  /(?:we'?ll|I'?ll|can)\s*beat\s*(any|the|their)/i, /guaranteed\s*approv/i, /approbation\s*garantie/i,
];
for (const pattern of FORBIDDEN_PATTERNS) {
  if (pattern.test(message)) { failures.push(`Content violation: ${pattern.source}`); pass = false; }
}

// 4. Message exists
if (!message || message.trim().length === 0) { failures.push('No message generated'); pass = false; }

return [{ json: { ...lead, _compliancePass: pass, _complianceFailures: failures, _complianceCheckedAt: now.toISOString() } }];

// Send via Twilio (SMS) or SendGrid (Email)

const lead = $input.first().json;
const channel = lead._channel;
const message = lead._message;
const subject = lead._emailSubject;

const TWILIO_ACCOUNT_SID = $env.TWILIO_ACCOUNT_SID || '';
const TWILIO_AUTH_TOKEN = $env.TWILIO_AUTH_TOKEN || '';
const TWILIO_FROM_NUMBER = $env.TWILIO_FROM_NUMBER || '';

let sendResult = { success: false, channel, error: null, messageId: null };

try {
  if (channel === 'sms') {
    const phones = lead.phones || [];
    const recipientPhone = phones[0]?.number || phones[0]?.phone || lead.phone || lead.mobile_phone || '';
    if (!recipientPhone) throw new Error('No phone number available for SMS');
    const twilioUrl = `https://api.twilio.com/2010-04-01/Accounts/${TWILIO_ACCOUNT_SID}/Messages.json`;
    const body = new URLSearchParams({ To: recipientPhone, From: TWILIO_FROM_NUMBER, Body: message });
    const response = await fetch(twilioUrl, {
      method: 'POST',
      headers: { 'Authorization': 'Basic ' + btoa(`${TWILIO_ACCOUNT_SID}:${TWILIO_AUTH_TOKEN}`), 'Content-Type': 'application/x-www-form-urlencoded' },
      body: body.toString(),
    });
    const result = await response.json();
    if (response.ok) sendResult = { success: true, channel: 'sms', messageId: result.sid, error: null };
    else throw new Error(result.message || `Twilio error: ${response.status}`);
  } else if (channel === 'email') {
    const emails = lead.emails || [];
    const recipientEmail = emails[0]?.address || emails[0]?.email || lead.email || '';
    if (!recipientEmail) throw new Error('No email address available');
    const SENDGRID_API_KEY = $env.SENDGRID_API_KEY || '';
    const FROM_EMAIL = $env.FROM_EMAIL || 'noreply@dealership.com';
    const FROM_NAME = $env.DEALERSHIP_NAME || 'Dealership';
    const emailPayload = {
      personalizations: [{ to: [{ email: recipientEmail }] }],
      from: { email: FROM_EMAIL, name: FROM_NAME },
      subject: subject || `Update from ${FROM_NAME}`,
      content: [{ type: 'text/plain', value: message }],
    };
    const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${SENDGRID_API_KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify(emailPayload),
    });
    if (response.ok || response.status === 202) sendResult = { success: true, channel: 'email', messageId: response.headers.get('x-message-id') || 'sent', error: null };
    else { const errText = await response.text(); throw new Error(`SendGrid error: ${response.status} ${errText}`); }
  }
} catch (err) {
  sendResult = { success: false, channel, error: err.message, messageId: null };
}

return [{ json: { ...lead, _sendResult: sendResult } }];

// PUT /v2/leads/:id — update result, rating, add comment with touch info

const lead = $input.first().json;
const ACTIVIX_API_URL = 'https://api.activix.ca/v2/leads';
const ACTIVIX_TOKEN = $env.ACTIVIX_API_TOKEN || '';

const touch = lead._touchNumber;
const channel = lead._channel;
const sendResult = lead._sendResult || {};
const now = new Date().toISOString();

const commentText = `[Nexus Auto] Touch ${touch} sent via ${channel} at ${now}. ${sendResult.success ? 'Delivered' : 'Failed: ' + (sendResult.error || 'unknown')}. MessageID: ${sendResult.messageId || 'N/A'}`;
const rating = touch <= 3 ? 3 : (touch <= 5 ? 2 : 1);

const updatePayload = { result: 'attempted', rating, comment: commentText };

let updateResult = { success: false, error: null };
try {
  const response = await fetch(`${ACTIVIX_API_URL}/${lead.id}`, {
    method: 'PUT',
    headers: { 'Authorization': `Bearer ${ACTIVIX_TOKEN}`, 'Content-Type': 'application/json', 'Accept': 'application/json' },
    body: JSON.stringify(updatePayload),
  });
  if (response.ok) updateResult = { success: true, error: null };
  else { const errText = await response.text(); throw new Error(`Activix update error: ${response.status} ${errText}`); }
} catch (err) {
  updateResult = { success: false, error: err.message };
}

return [{ json: { leadId: lead.id, firstName: lead.first_name, touchNumber: touch, channel, locale: lead._locale, sendResult, activixUpdate: updateResult, processedAt: now } }];

// Log compliance failure and continue to next lead
const lead = $input.first().json;
const now = new Date().toISOString();

const logEntry = {
  leadId: lead.id,
  firstName: lead.first_name || 'unknown',
  touchNumber: lead._touchNumber,
  channel: lead._channel,
  locale: lead._locale,
  complianceFailures: lead._complianceFailures || [],
  skippedAt: now,
  reason: 'Compliance check failed -- message not sent',
};

console.log('[Compliance Fail]', JSON.stringify(logEntry));

return [{ json: logEntry }];
